WHERE item_no = #{itemNo}
  AND user_id = #{keyUserId}


DELETE FROM cm_topo_link_multi
WHERE link_no IN (
    SELECT K.link_no
    FROM cm_topo_link K
    INNER JOIN (
        SELECT A.item_no
        FROM cm_topo_item A
        INNER JOIN (
            SELECT sub_no FROM cm_topo_leaf
            WHERE grp_no = #{mngNo} AND user_id = #{keyUserId}
        ) B ON A.grp_no = B.sub_no
        WHERE A.user_id = #{keyUserId}
    ) L ON K.item_no1 = L.item_no OR K.item_no2 = L.item_no
    WHERE K.user_id = #{keyUserId}
)
  AND user_id = #{keyUserId};


DELETE FROM cm_topo_link
WHERE link_no IN (
    SELECT K.link_no
    FROM cm_topo_link K
    INNER JOIN (
        SELECT A.item_no
        FROM cm_topo_item A
        INNER JOIN (
            SELECT sub_no FROM cm_topo_leaf
            WHERE grp_no = #{mngNo} AND user_id = #{keyUserId}
        ) B ON A.grp_no = B.sub_no
        WHERE A.user_id = #{keyUserId}
    ) L ON K.item_no1 = L.item_no OR K.item_no2 = L.item_no
    WHERE K.user_id = #{keyUserId}
)
  AND user_id = #{keyUserId};


DELETE FROM cm_topo_link
WHERE user_id = #{keyUserId}
  AND grp_no = #{mngNo};


DELETE FROM cm_topo_etc
WHERE user_id = #{keyUserId}
  AND item_no IN (
      SELECT A.item_no
      FROM cm_topo_item A
      INNER JOIN cm_topo_leaf B ON A.user_id = B.user_id AND A.grp_no = B.sub_no
      WHERE A.dev_kind1 = 'ETC'
        AND A.user_id = #{keyUserId}
        AND B.grp_no = #{mngNo}
  );


DELETE FROM cm_topo_item
WHERE grp_no IN (
    SELECT sub_no FROM cm_topo_leaf
    WHERE user_id = #{keyUserId} AND grp_no = #{mngNo}
)
  AND user_id = #{keyUserId};


DELETE FROM cm_topo_draw_tool
WHERE grp_no IN (
    SELECT sub_no FROM cm_topo_leaf
    WHERE user_id = #{keyUserId} AND grp_no = #{mngNo}
)
  AND user_id = #{keyUserId};


DELETE FROM cm_topo_item
WHERE item_no = #{itemNo}
  AND dev_kind1 = 'GRP'
  AND user_id = #{keyUserId};


DELETE FROM cm_topo_group
WHERE grp_no IN (
    SELECT B.grp_no
    FROM cm_topo_leaf A
    INNER JOIN cm_topo_group B ON A.sub_no = B.grp_no AND A.user_id = B.user_id
    WHERE A.grp_no = #{mngNo}
      AND A.user_id = #{keyUserId}
)
  AND user_id = #{keyUserId};


UPDATE cm_topo_user
SET slide_grp_conf =
    CASE
        WHEN slide_grp_conf::text LIKE '%' || #{mngNo} || '%'
        THEN REPLACE(REPLACE(REPLACE(
            CONCAT(
                SUBSTRING(slide_grp_conf::text, 1, POSITION(#{mngNo}::text IN slide_grp_conf::text) - 1),
                SUBSTRING(slide_grp_conf::text, POSITION(#{mngNo}::text IN slide_grp_conf::text) + LENGTH(#{mngNo}::text))
            ),
            ',,', ','), ',","', '","'), '":",', '":"')
        ELSE slide_grp_conf::text
    END
WHERE slide_grp_conf IS NOT NULL;

